package com.cardiofit.flink.models;

import com.fasterxml.jackson.annotation.JsonProperty;
import java.io.Serializable;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;

/**
 * ComposedAlert represents a high-level alert composed from multiple detection sources
 * Generated by Module 6 (Alert Composition & Deduplication)
 *
 * ComposedAlert aggregates evidence from:
 * - Module 2: Threshold-based detection (SimpleAlert)
 * - Module 4: CEP pattern matching (ClinicalAlert)
 * - Module 5: ML predictions (enrichment)
 *
 * Features:
 * - Multi-source evidence aggregation
 * - Confidence scoring based on detection consensus
 * - Recommended clinical actions
 * - Deduplication tracking (suppression count)
 * - Full audit trail of contributing sources
 *
 * Example usage:
 * <pre>
 * ComposedAlert alert = ComposedAlert.builder()
 *     .patientId("P12345")
 *     .severity(AlertSeverity.CRITICAL)
 *     .confidence(0.95)
 *     .addSource("MODULE_2_THRESHOLD")
 *     .addSource("MODULE_4_CEP_SEPSIS")
 *     .addEvidence("heart_rate", 165)
 *     .addEvidence("lactate", 3.5)
 *     .addEvidence("sepsis_pattern_matched", true)
 *     .addRecommendedAction("ESCALATE_TO_PHYSICIAN")
 *     .addRecommendedAction("INCREASE_MONITORING")
 *     .compositionStrategy(CompositionStrategy.COMBINED)
 *     .build();
 * </pre>
 */
public class ComposedAlert implements Serializable {
    private static final long serialVersionUID = 1L;

    @JsonProperty("alert_id")
    private String alertId;

    @JsonProperty("patient_id")
    private String patientId;

    @JsonProperty("severity")
    private AlertSeverity severity;

    @JsonProperty("confidence")
    private double confidence;  // 0.0 to 1.0

    @JsonProperty("sources")
    private List<String> sources;  // Contributing modules: "MODULE_2_THRESHOLD", "MODULE_4_CEP_SEPSIS", etc.

    @JsonProperty("evidence")
    private Map<String, Object> evidence;  // All supporting clinical data from contributing alerts

    @JsonProperty("recommended_actions")
    private List<String> recommendedActions;  // Clinical actions: "ESCALATE_TO_PHYSICIAN", "INCREASE_MONITORING", etc.

    @JsonProperty("suppression_count")
    private int suppressionCount;  // How many duplicate alerts were suppressed

    @JsonProperty("last_updated")
    private long lastUpdated;

    @JsonProperty("composition_strategy")
    private CompositionStrategy compositionStrategy;

    public ComposedAlert() {
        this.sources = new ArrayList<>();
        this.evidence = new HashMap<>();
        this.recommendedActions = new ArrayList<>();
        this.suppressionCount = 0;
        this.lastUpdated = System.currentTimeMillis();
    }

    private ComposedAlert(Builder builder) {
        this.alertId = builder.alertId;
        this.patientId = builder.patientId;
        this.severity = builder.severity;
        this.confidence = builder.confidence;
        this.sources = builder.sources;
        this.evidence = builder.evidence;
        this.recommendedActions = builder.recommendedActions;
        this.suppressionCount = builder.suppressionCount;
        this.lastUpdated = builder.lastUpdated;
        this.compositionStrategy = builder.compositionStrategy;
    }

    /**
     * Add a contributing source module to the alert
     * @param source Module identifier (e.g., "MODULE_2_THRESHOLD", "MODULE_4_CEP_SEPSIS")
     */
    public void addSource(String source) {
        if (source != null && !this.sources.contains(source)) {
            this.sources.add(source);
            this.lastUpdated = System.currentTimeMillis();
        }
    }

    /**
     * Increment the suppression count for deduplication tracking
     */
    public void incrementSuppressionCount() {
        this.suppressionCount++;
        this.lastUpdated = System.currentTimeMillis();
    }

    // Builder pattern
    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private String alertId;
        private String patientId;
        private AlertSeverity severity;
        private double confidence;
        private List<String> sources = new ArrayList<>();
        private Map<String, Object> evidence = new HashMap<>();
        private List<String> recommendedActions = new ArrayList<>();
        private int suppressionCount = 0;
        private long lastUpdated;
        private CompositionStrategy compositionStrategy;

        public Builder alertId(String alertId) {
            this.alertId = alertId;
            return this;
        }

        public Builder patientId(String patientId) {
            this.patientId = patientId;
            return this;
        }

        public Builder severity(AlertSeverity severity) {
            this.severity = severity;
            return this;
        }

        public Builder confidence(double confidence) {
            this.confidence = confidence;
            return this;
        }

        public Builder sources(List<String> sources) {
            this.sources = sources != null ? new ArrayList<>(sources) : new ArrayList<>();
            return this;
        }

        public Builder addSource(String source) {
            if (source != null && !this.sources.contains(source)) {
                this.sources.add(source);
            }
            return this;
        }

        public Builder evidence(Map<String, Object> evidence) {
            this.evidence = evidence != null ? new HashMap<>(evidence) : new HashMap<>();
            return this;
        }

        public Builder addEvidence(String key, Object value) {
            this.evidence.put(key, value);
            return this;
        }

        public Builder recommendedActions(List<String> recommendedActions) {
            this.recommendedActions = recommendedActions != null ? new ArrayList<>(recommendedActions) : new ArrayList<>();
            return this;
        }

        public Builder addRecommendedAction(String action) {
            if (action != null && !this.recommendedActions.contains(action)) {
                this.recommendedActions.add(action);
            }
            return this;
        }

        public Builder suppressionCount(int suppressionCount) {
            this.suppressionCount = suppressionCount;
            return this;
        }

        public Builder lastUpdated(long lastUpdated) {
            this.lastUpdated = lastUpdated;
            return this;
        }

        public Builder compositionStrategy(CompositionStrategy compositionStrategy) {
            this.compositionStrategy = compositionStrategy;
            return this;
        }

        public ComposedAlert build() {
            // Validation
            if (patientId == null || patientId.trim().isEmpty()) {
                throw new IllegalArgumentException("Patient ID is required");
            }
            if (severity == null) {
                throw new IllegalArgumentException("Severity is required");
            }
            if (confidence < 0.0 || confidence > 1.0) {
                throw new IllegalArgumentException("Confidence must be between 0.0 and 1.0");
            }
            if (sources.isEmpty()) {
                throw new IllegalArgumentException("At least one source module is required");
            }

            // Set defaults
            if (alertId == null) {
                this.alertId = UUID.randomUUID().toString();
            }
            if (lastUpdated == 0) {
                this.lastUpdated = System.currentTimeMillis();
            }
            if (compositionStrategy == null) {
                // Infer strategy from sources
                if (sources.contains("MODULE_2_THRESHOLD") && sources.stream().anyMatch(s -> s.contains("CEP"))) {
                    this.compositionStrategy = CompositionStrategy.COMBINED;
                } else if (sources.stream().anyMatch(s -> s.contains("CEP"))) {
                    this.compositionStrategy = CompositionStrategy.CEP_ONLY;
                } else {
                    this.compositionStrategy = CompositionStrategy.THRESHOLD_ONLY;
                }
            }

            return new ComposedAlert(this);
        }
    }

    // Getters and Setters
    public String getAlertId() { return alertId; }
    public void setAlertId(String alertId) { this.alertId = alertId; }

    public String getPatientId() { return patientId; }
    public void setPatientId(String patientId) { this.patientId = patientId; }

    public AlertSeverity getSeverity() { return severity; }
    public void setSeverity(AlertSeverity severity) { this.severity = severity; }

    public double getConfidence() { return confidence; }
    public void setConfidence(double confidence) { this.confidence = confidence; }

    public List<String> getSources() { return sources; }
    public void setSources(List<String> sources) { this.sources = sources; }

    public Map<String, Object> getEvidence() { return evidence; }
    public void setEvidence(Map<String, Object> evidence) { this.evidence = evidence; }

    public List<String> getRecommendedActions() { return recommendedActions; }
    public void setRecommendedActions(List<String> recommendedActions) { this.recommendedActions = recommendedActions; }

    public int getSuppressionCount() { return suppressionCount; }
    public void setSuppressionCount(int suppressionCount) { this.suppressionCount = suppressionCount; }

    public long getLastUpdated() { return lastUpdated; }
    public void setLastUpdated(long lastUpdated) { this.lastUpdated = lastUpdated; }

    public CompositionStrategy getCompositionStrategy() { return compositionStrategy; }
    public void setCompositionStrategy(CompositionStrategy compositionStrategy) { this.compositionStrategy = compositionStrategy; }

    @Override
    public String toString() {
        return "ComposedAlert{" +
                "alertId='" + alertId + '\'' +
                ", patientId='" + patientId + '\'' +
                ", severity=" + severity +
                ", confidence=" + confidence +
                ", sources=" + sources +
                ", recommendedActions=" + recommendedActions +
                ", suppressionCount=" + suppressionCount +
                ", compositionStrategy=" + compositionStrategy +
                ", lastUpdated=" + lastUpdated +
                '}';
    }
}
